final:
module RefModule(
    input [3:0] a,
    input [3:0] b,
    input [1:0] opcode,
    output [3:0] result
);reg [3:0] final_sig;

always @(*) begin
    case(opcode)
        2'b00: final_sig = a + b;
        2'b01: final_sig = a - b;
        2'b10: final_sig = a & b;
        2'b11: final_sig = a | b;
    endcase
end

assign result = final_sig;

endmodule
